@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@(Notifications?.Count ?? 0)</span></h1>

@if (Notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (Notifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in Notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item">
                <strong>@notification.Message</strong>
                <br />
                <small class="text-muted">@notification.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<Notification>? Notifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if not restored from prerender state
        Notifications ??= await NotificationService.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender never runs during prerender — safe to start polling
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

            var lastId = Notifications?.MaxBy(n => n.Id)?.Id ?? 0;
            var newer = await NotificationService.GetNotificationsSinceAsync(lastId);

            if (newer.Count > 0)
            {
                Notifications ??= new();
                Notifications.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

